import React, { useState, useEffect } from 'react';
import './App.css';

const API_BASE = 'http://localhost:80/api';

function App() {
    const [selectedBackend, setSelectedBackend] = useState('nodejs');
    const [backends, setBackends] = useState([
        { id: 'nodejs', name: 'Node.js', tech: 'JavaScript', status: 'unknown' },
        { id: 'fastapi', name: 'FastAPI', tech: 'Python', status: 'unknown' },
        { id: 'springboot', name: 'Spring Boot', tech: 'Java', status: 'unknown' },
        { id: 'dotnet', name: '.NET', tech: 'C#', status: 'unknown' }
    ]);
    const [tasks, setTasks] = useState([]);
    const [title, setTitle] = useState('');
    const [description, setDescription] = useState('');
    const [message, setMessage] = useState('');
    const [loading, setLoading] = useState(false);

    // Check health of all backends
    const checkHealth = async () => {
        const updated = [...backends];
        for (let i = 0; i < updated.length; i++) {
            try {
                const res = await fetch(`${API_BASE}/${updated[i].id}/health`);
                updated[i].status = res.ok ? 'online' : 'offline';
            } catch {
                updated[i].status = 'offline';
            }
        }
        setBackends(updated);
    };

    // Fetch tasks
    const fetchTasks = async () => {
        setLoading(true);
        try {
            const res = await fetch(`${API_BASE}/${selectedBackend}/tasks`);
            const data = await res.json();
            if (data.success) {
                setTasks(data.data);
                setMessage(`Connected to ${data.backend}`);
            }
        } catch (error) {
            setMessage(`Error: Cannot connect to ${selectedBackend}`);
        }
        setLoading(false);
    };

    // Select backend
    const selectBackend = (id) => {
        if (backends.find(b => b.id === id)?.status === 'online') {
            setSelectedBackend(id);
            fetchTasks();
        } else {
            setMessage(`${id} is offline`);
        }
    };

    // Add task
    const addTask = async (e) => {
        e.preventDefault();
        if (!title.trim()) return;

        try {
            const res = await fetch(`${API_BASE}/${selectedBackend}/tasks`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ title, description })
            });
            const data = await res.json();
            if (data.success) {
                setMessage('Task added!');
                setTitle('');
                setDescription('');
                fetchTasks();
            }
        } catch (error) {
            setMessage('Error adding task');
        }
    };

    // Delete task
    const deleteTask = async (id) => {
        if (window.confirm('Delete this task?')) {
            try {
                await fetch(`${API_BASE}/${selectedBackend}/tasks/${id}`, { method: 'DELETE' });
                setMessage('Task deleted!');
                fetchTasks();
            } catch (error) {
                setMessage('Error deleting task');
            }
        }
    };

    useEffect(() => {
        checkHealth();
        fetchTasks();
        const interval = setInterval(checkHealth, 30000);
        return () => clearInterval(interval);
    }, [selectedBackend]);

    return (
        <div className="container">
            <div className="header">
                <h1>Multi-Backend Task Manager</h1>
                <p>React → Nginx → Node.js | FastAPI | Spring Boot | .NET → MySQL</p>
            </div>

            {message && (
                <div className="message success">
                    {message}
                    <button className="close-btn" onClick={() => setMessage('')}>×</button>
                </div>
            )}

            <div className="backends-grid">
                {backends.map(backend => (
                    <div 
                        key={backend.id}
                        className={`backend-card ${backend.id} ${backend.status === 'offline' ? 'offline' : ''} ${selectedBackend === backend.id ? 'active' : ''}`}
                        onClick={() => selectBackend(backend.id)}
                    >
                        <div className="backend-name">{backend.name}</div>
                        <div className="backend-tech">{backend.tech}</div>
                        <span className={`status-badge ${backend.status === 'online' ? 'status-online' : 'status-offline'}`}>
                            {backend.status === 'online' ? 'Online' : 'Offline'}
                        </span>
                        {selectedBackend === backend.id && (
                            <div className="active-badge">✓ Active</div>
                        )}
                    </div>
                ))}
            </div>

            <div className="loadbalancer-info">
                Active: {backends.find(b => b.id === selectedBackend)?.name} via Nginx (Round Robin)
            </div>

            <div className="task-form">
                <h3>Add New Task</h3>
                <form onSubmit={addTask}>
                    <input
                        type="text"
                        placeholder="Task Title"
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        required
                    />
                    <textarea
                        placeholder="Task Description"
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        rows="3"
                    />
                    <button type="submit">Add Task</button>
                </form>
            </div>

            <div className="tasks-table">
                <table>
                    <thead>
                        <tr>
                            <th>ID</th>
                            <th>Title</th>
                            <th>Description</th>
                            <th>Status</th>
                            <th>Created At</th>
                            <th>Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        {loading ? (
                            <tr><td colSpan="6" className="loading">Loading...</td></tr>
                        ) : tasks.length === 0 ? (
                            <tr><td colSpan="6" style={{ textAlign: 'center' }}>No tasks</td></tr>
                        ) : (
                            tasks.map(task => (
                                <tr key={task.id}>
                                    <td>{task.id}</td>
                                    <td><strong>{task.title}</strong></td>
                                    <td>{task.description || '-'}</td>
                                    <td>
                                        <span className={task.status === 'completed' ? 'status-completed' : 'status-pending'}>
                                            {task.status || 'pending'}
                                        </span>
                                    </td>
                                    <td>{new Date(task.created_at).toLocaleString()}</td>
                                    <td>
                                        <button onClick={() => deleteTask(task.id)} className="delete-btn">Delete</button>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

export default App;
